Javascript.isReadOnly:
var allWarrants = Services.getValue(AllWarrants.dataBinding);
if (! CaseManUtils.isBlank(allWarrants))
{
	if (allWarrants == "Y")
	{
		return true;
	}
	else
	{
		return false;
	}
}
else
{
	//TD4183 Kevin Gichohi (EDS) - 10 Aug 2006: The case number field should be read only if the box is unchecked on entry i.e. allWarrants is blank or null.
	return false;
}

Javascript.logic:
var allWarrants = Services.getValue(AllWarrants.dataBinding);
if (! CaseManUtils.isBlank(allWarrants))
{
	if (allWarrants == "Y")
	{
		Services.setValue(CaseNumber.dataBinding, "");
	}
}

var caseNumber = Services.getValue(CaseNumber.dataBinding);
var warrantNumber = Services.getValue(WarrantNumber.dataBinding);	
if (!CaseManUtils.isBlank(caseNumber) && !CaseManUtils.isBlank(warrantNumber))
{
	if (CaseNumber.validate() == null)
	{
		searchWarrants();
	}
}

Javascript.miscCode:

CaseNumber.validate = function()
{
	var value = Services.getValue(CaseNumber.dataBinding);
	var errCode = null;
	if ( ! CaseManUtils.isBlank(value) )
	{
		errCode = CaseManValidationHelper.validateCaseNumber(value);
	}
	return errCode;
}
